		t,
		dir,
		"manager.jsonl",
		"manager-session",
		dir,
		assistantLine("manager"),
	)
	other := writePiSession(
		t,
		dir,
		"other.jsonl",
		"other-session",
		dir,
		assistantLine("other"),
	)
	state := ManagerState{
		Workflow:  testWorkflowState(t, qrspi.NodeResearch, nil),
		Rotations: RotationState{Config: RotationConfig{ThresholdPercent: 75}},
	}
	opts := RotationRequestOptions{
		StateFile:   filepath.Join(dir, "state.json"),
		Role:        RotationRoleManager,
		SessionPath: source,
		Usage:       usagePercentInput(75),
	}
	now := time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC)
	next, status, err := requestSessionRotation(state, opts, now)
	if err != nil {
		t.Fatalf("manager request error = %v", err)
	}
	if !status.Requested || !sameCleanPath(next.ManagerSessionPath, source) ||
		next.Rotations.Manager == nil {
		t.Fatalf("status/state = %+v / %+v", status, next)
	}
	for _, want := range []string{status.RotationID, string(qrspi.NodeResearch), ".pi/skills/q-manager-handoff/SKILL.md", "Do not run /new"} {
		if !strings.Contains(status.Prompt, want) {
