		}
	}
	stale := opts
	stale.SessionPath = other
	mutated, _, err := requestSessionRotation(next, stale, now.Add(time.Second))
	if err == nil {
		t.Fatal("stale manager session accepted")
	}
	if !sameCleanPath(mutated.ManagerSessionPath, source) ||
		mutated.Rotations.Manager.ID != status.RotationID {
		t.Fatalf("stale request mutated manager state: %+v", mutated)
	}
}

func TestCompleteChildRotationTransitionsOnlyMatchingRequest(t *testing.T) {
	state, opts := rotationChildFixture(t)
	opts.Usage = usagePercentInput(75)
	now := time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC)
	requested, _, err := requestSessionRotation(state, opts, now)
	if err != nil {
		t.Fatal(err)
	}
	source := *requested.ActiveChild
	continuation := ChildRunRef{
		ID:                     "successor",
		Stage:                  source.Stage,
		LaunchKind:             ChildLaunchResumeHandoff,
		ContinuationOf:         source.ID,
		ContinuationArtifact:   "thoughts/example/handoffs/research.md",
		ContinuationDeliveryID: "delivery-1",
	}
	completed := completeChildRotation(
		requested,
		source,
		continuation,
		now.Add(time.Second),
	)
	if completed.Rotations.Child.Phase != RotationSuccessorReady ||
		completed.Rotations.Child.SuccessorChildID != continuation.ID ||
		completed.Rotations.Child.HandoffArtifact != continuation.ContinuationArtifact {
		t.Fatalf("completed rotation = %+v", completed.Rotations.Child)
	}

	mismatched := requested
	badSource := source
	badSource.Generation++
	mismatched = completeChildRotation(
		mismatched,
		badSource,
		continuation,
		now.Add(time.Second),
	)
	if mismatched.Rotations.Child.Phase != RotationRequested {
		t.Fatalf("mismatched rotation advanced: %+v", mismatched.Rotations.Child)
	}

	generic := requested
	generic.Rotations.Child = nil
	generic = completeChildRotation(generic, source, continuation, now.Add(time.Second))
	if generic.Rotations.Child != nil {
		t.Fatalf("generic handoff created rotation: %+v", generic.Rotations.Child)
	}
}

