			ID: "replacement", Generation: 1, LifecycleStatus: "running",
			LaunchKind: ChildLaunchResumeHandoff, ContinuationDeliveryID: "wake-1",
		},
	})
	tmux := &recordingTmux{}
	if err := RunManagerReady(
