+ 652 		return nil, fmt.Errorf("manager rotation %q does not match %q", rotationID, rotation.ID)
+ 653 	}
+ 654 	if !sameCleanPath(rotation.SourceSessionPath, sourceSession) {
+ 655 		return nil, fmt.Errorf(
+ 656 			"manager source session %q does not match rotation source %q",
+ 657 			sourceSession,
+ 658 			rotation.SourceSessionPath,
+ 659 		)
+ 660 	}
+ 661 	return rotation, nil
+ 662 }
