+ 664 func validateManagerHandoffResult(
+ 665 	state ManagerState,
+ 666 	rotation SessionRotation,
+ 667 	sessionPath string,
+ 668 ) (ManagerHandoffResult, ManagerHandoffFrontmatter, string, error) {
+ 669 	if !sameCleanPath(rotation.SourceSessionPath, sessionPath) {
+ 670 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", errors.New(
+ 671 			"manager handoff source session does not own the rotation",
+ 672 		)
+ 673 	}
+ 674 	text, err := ExtractFinalAssistantTextFromSession(sessionPath)
+ 675 	if err != nil {
+ 676 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+ 677 	}
+ 678 	rawYAML, err := workflowqrspi.ExtractQRSPIResultYAML(text)
+ 679 	if err != nil {
+ 680 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+ 681 	}
+ 682 	var envelope struct {
+ 683 		Result ManagerHandoffResult `yaml:"qrspi_result"`
+ 684 	}
+ 685 	if err := yaml.Unmarshal([]byte(rawYAML), &envelope); err != nil {
+ 686 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", fmt.Errorf(
+ 687 			"parse manager handoff result: %w",
+ 688 			err,
+ 689 		)
+ 690 	}
+ 691 	result := envelope.Result
+ 692 	if result.Stage != "q-manager" || result.Status != "handoff" ||
+ 693 		strings.TrimSpace(result.Outcome) != "" || strings.TrimSpace(result.Artifact) == "" {
+ 694 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", fmt.Errorf(
+ 695 			"manager handoff result must use stage q-manager, status handoff, no outcome, and one artifact",
+ 696 		)
+ 697 	}
+ 698 	sourceCwd := firstNonEmpty(strings.TrimSpace(state.SourceCwd), strings.TrimSpace(state.RepoID))
+ 699 	artifact, err := resolvePlanArtifact(
+ 700 		state.RepoID,
+ 701 		state.CanonicalPlanDir,
+ 702 		sourceCwd,
+ 703 		result.Artifact,
+ 704 	)
+ 705 	if err != nil {
+ 706 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+ 707 	}
+ 708 	frontmatter, err := readManagerHandoffFrontmatter(artifact)
+ 709 	if err != nil {
+ 710 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+ 711 	}
+ 712 	if frontmatter.Stage != "q-manager" || frontmatter.Status != "in_progress" ||
+ 713 		frontmatter.HandoffType != "q-manager-operational" ||
+ 714 		frontmatter.RotationID != rotation.ID {
+ 715 		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", fmt.Errorf(
+ 716 			"manager handoff frontmatter does not match rotation %q",
+ 717 			rotation.ID,
+ 718 		)
+ 719 	}
+ 720 	return result, frontmatter, artifact, nil
+ 721 }
+ 722 
+ 723 func readManagerHandoffFrontmatter(path string) (ManagerHandoffFrontmatter, error) {
+ 724 	file, err := os.Open(path)
+ 725 	if err != nil {
+ 726 		return ManagerHandoffFrontmatter{}, err
+ 727 	}
+ 728 	defer file.Close()
+ 729 	scanner := bufio.NewScanner(file)
+ 730 	if !scanner.Scan() || strings.TrimSpace(scanner.Text()) != "---" {
+ 731 		return ManagerHandoffFrontmatter{}, errors.New("manager handoff must start with YAML frontmatter")
+ 732 	}
+ 733 	var raw strings.Builder
+ 734 	closed := false
+ 735 	for scanner.Scan() {
+ 736 		if strings.TrimSpace(scanner.Text()) == "---" {
+ 737 			closed = true
+ 738 			break
+ 739 		}
+ 740 		raw.WriteString(scanner.Text())
+ 741 		raw.WriteByte('\n')
+ 742 	}
+ 743 	if err := scanner.Err(); err != nil {
+ 744 		return ManagerHandoffFrontmatter{}, err
+ 745 	}
+ 746 	if !closed {
+ 747 		return ManagerHandoffFrontmatter{}, errors.New("manager handoff frontmatter is not closed")
+ 748 	}
+ 749 	var frontmatter ManagerHandoffFrontmatter
+ 750 	if err := yaml.Unmarshal([]byte(raw.String()), &frontmatter); err != nil {
+ 751 		return ManagerHandoffFrontmatter{}, fmt.Errorf("parse manager handoff frontmatter: %w", err)
+ 752 	}
+ 753 	return frontmatter, nil
+ 754 }
