+ 807 func RunManagerRotationClaim(
+ 808 	ctx context.Context,
+ 809 	opts ManagerRotationClaimOptions,
+ 810 	d deps,
+ 811 	out io.Writer,
+ 812 ) error {
+ 813 	if strings.TrimSpace(opts.StateFile) == "" || strings.TrimSpace(opts.RotationID) == "" ||
+ 814 		strings.TrimSpace(opts.ManagerPane) == "" || strings.TrimSpace(opts.PreviousSessionPath) == "" ||
+ 815 		strings.TrimSpace(opts.SuccessorSessionPath) == "" {
+ 816 		return errors.New("state-file, rotation-id, manager-pane, previous-session-path, and session-path are required")
+ 817 	}
+ 818 	previous, err := canonicalSessionPath(opts.PreviousSessionPath)
+ 819 	if err != nil {
+ 820 		return err
+ 821 	}
+ 822 	successor, err := canonicalSessionPath(opts.SuccessorSessionPath)
+ 823 	if err != nil {
+ 824 		return err
+ 825 	}
+ 826 	opts.PreviousSessionPath = previous
+ 827 	opts.SuccessorSessionPath = successor
+ 828 	out = ensureWriter(out)
+ 829 	store := stateStore(d, "", clockOrNow(d))
+ 830 	lock, err := store.AcquireOperationLock(ctx, opts.StateFile)
+ 831 	if err != nil {
+ 832 		return err
+ 833 	}
+ 834 	defer lock.Release()
+ 835 	state, err := store.Load(opts.StateFile)
+ 836 	if err != nil {
+ 837 		return err
+ 838 	}
+ 839 	next, result, err := claimManagerSuccessor(state, opts, clockOrNow(d)())
+ 840 	if err != nil {
+ 841 		return err
+ 842 	}
+ 843 	if err := store.Save(opts.StateFile, next); err != nil {
+ 844 		return err
+ 845 	}
+ 846 	if strings.EqualFold(strings.TrimSpace(opts.Output), "json") {
+ 847 		return json.NewEncoder(out).Encode(result)
+ 848 	}
+ 849 	if result.Claimed {
+ 850 		_, err = fmt.Fprintf(out, "manager rotation claimed: %s\n", opts.RotationID)
+ 851 	} else {
+ 852 		_, err = fmt.Fprintf(out, "manager rotation claim skipped: %s\n", result.Reason)
+ 853 	}
+ 854 	return err
+ 855 }
