+ 857 func claimManagerSuccessor(
+ 858 	state ManagerState,
+ 859 	opts ManagerRotationClaimOptions,
+ 860 	now time.Time,
+ 861 ) (ManagerState, ManagerRotationClaimResult, error) {
+ 862 	original := state
+ 863 	rotation := state.Rotations.Manager
+ 864 	if rotation == nil || rotation.Role != RotationRoleManager ||
+ 865 		rotation.ID != strings.TrimSpace(opts.RotationID) {
+ 866 		return original, ManagerRotationClaimResult{}, errors.New("manager rotation claim does not match pending rotation")
+ 867 	}
+ 868 	if rotation.Phase != RotationReplacing {
+ 869 		return original, ManagerRotationClaimResult{}, fmt.Errorf(
+ 870 			"manager rotation %q is in phase %q, not replacing",
+ 871 			rotation.ID,
+ 872 			rotation.Phase,
+ 873 		)
+ 874 	}
+ 875 	paneID := managerDeliveryPane(state)
+ 876 	if paneID == "" || paneID != strings.TrimSpace(opts.ManagerPane) {
+ 877 		return original, ManagerRotationClaimResult{}, fmt.Errorf(
+ 878 			"manager pane %q does not match persisted pane %q",
+ 879 			opts.ManagerPane,
+ 880 			paneID,
+ 881 		)
+ 882 	}
+ 883 	if !sameCleanPath(rotation.SourceSessionPath, opts.PreviousSessionPath) {
+ 884 		return original, ManagerRotationClaimResult{}, errors.New("previous session does not match rotation source")
+ 885 	}
+ 886 	if sameCleanPath(opts.PreviousSessionPath, opts.SuccessorSessionPath) {
+ 887 		return original, ManagerRotationClaimResult{}, errors.New("successor session must differ from source session")
+ 888 	}
+ 889 	if rotation.SuccessorSessionPath != "" &&
+ 890 		!sameCleanPath(rotation.SuccessorSessionPath, opts.SuccessorSessionPath) {
+ 891 		return original, ManagerRotationClaimResult{}, errors.New("a different successor already claimed the rotation")
+ 892 	}
+ 893 	next := *rotation
+ 894 	next.SuccessorSessionPath = opts.SuccessorSessionPath
+ 895 	next.UpdatedAt = now.Format(time.RFC3339Nano)
+ 896 	next.LastError = ""
+ 897 	state.Rotations.Manager = &next
+ 898 	state.ManagerSessionPath = opts.SuccessorSessionPath
+ 899 	return state, ManagerRotationClaimResult{
+ 900 		Claimed: true,
+ 901 		Reason:  "claimed",
+ 902 		Kickoff: managerRotationKickoff(state, next, opts.StateFile),
+ 903 	}, nil
+ 904 }
+ 905 
+ 906 func managerRotationKickoff(state ManagerState, rotation SessionRotation, stateFile string) string {
+ 907 	return fmt.Sprintf(
+ 908 		"Continue q-manager in this fresh same-pane session. Read .pi/skills/q-manager/SKILL.md, then read the operational handoff %s. Current graph node: %s. Local manager state: %s. Resume the wake-driven manager loop from the handoff; do not duplicate any persisted child continuation.",
+ 909 		rotation.HandoffArtifact,
+ 910 		state.Workflow.CurrentNodeID,
+ 911 		stateFile,
+ 912 	)
+ 913 }
