+ 915 func acknowledgeManagerRotationReady(
+ 916 	state ManagerState,
+ 917 	opts ManagerReadyOptions,
+ 918 	now time.Time,
+ 919 ) (ManagerState, error) {
+ 920 	rotation := state.Rotations.Manager
+ 921 	if rotation == nil {
+ 922 		return state, nil
+ 923 	}
+ 924 	if rotation.Phase == RotationSuccessorReady {
+ 925 		if strings.TrimSpace(opts.RotationID) != "" && opts.RotationID != rotation.ID {
+ 926 			return state, errors.New("manager-ready rotation ID does not match current rotation")
+ 927 		}
+ 928 		if strings.TrimSpace(opts.SessionPath) != "" &&
+ 929 			!sameCleanPath(opts.SessionPath, rotation.SuccessorSessionPath) {
+ 930 			return state, errors.New("manager-ready session does not match current successor")
+ 931 		}
+ 932 		return state, nil
+ 933 	}
+ 934 	if rotation.Phase != RotationReplacing {
+ 935 		return state, nil
+ 936 	}
+ 937 	if strings.TrimSpace(opts.RotationID) == "" || opts.RotationID != rotation.ID {
+ 938 		return state, errors.New("manager-ready requires the exact pending rotation ID")
+ 939 	}
+ 940 	if strings.TrimSpace(opts.SessionPath) == "" {
+ 941 		return state, errors.New("manager-ready requires the successor session path")
+ 942 	}
+ 943 	sessionPath, err := canonicalSessionPath(opts.SessionPath)
+ 944 	if err != nil {
+ 945 		return state, err
+ 946 	}
+ 947 	if !sameCleanPath(sessionPath, rotation.SuccessorSessionPath) ||
+ 948 		!sameCleanPath(sessionPath, state.ManagerSessionPath) {
+ 949 		return state, errors.New("manager-ready session does not own the claimed successor")
+ 950 	}
+ 951 	paneID := managerDeliveryPane(state)
+ 952 	if strings.TrimSpace(opts.ManagerPane) == "" || strings.TrimSpace(opts.ManagerPane) != paneID {
+ 953 		return state, errors.New("manager-ready pane does not match persisted replacement pane")
+ 954 	}
+ 955 	next := *rotation
+ 956 	next.Phase = RotationSuccessorReady
+ 957 	next.UpdatedAt = now.Format(time.RFC3339Nano)
+ 958 	next.LastError = ""
+ 959 	state.Rotations.Manager = &next
+ 960 	state.Delivery.Status = "ready"
+ 961 	state.LastActionCard = nil
+ 962 	return state, nil
+ 963 }
