+func RunManagerRotationComplete(
+	ctx context.Context,
+	opts ManagerRotationCompleteOptions,
+	d deps,
+	out io.Writer,
+) error {
+	if err := validateManagerRotationCompleteOptions(opts); err != nil {
+		return err
+	}
+	sourceSession, err := canonicalSessionPath(opts.SessionPath)
+	if err != nil {
+		return err
+	}
+	opts.SessionPath = sourceSession
+	out = ensureWriter(out)
+	store := stateStore(d, "", clockOrNow(d))
+	lock, err := store.AcquireOperationLock(ctx, opts.StateFile)
+	if err != nil {
+		return err
+	}
+	defer lock.Release()
+
+	state, err := store.Load(opts.StateFile)
+	if err != nil {
+		return err
+	}
+	rotation, err := requireManagerRotation(state, opts.RotationID, sourceSession)
+	if err != nil {
+		return err
+	}
+	if rotation.Phase == RotationSuccessorReady ||
+		(rotation.Phase == RotationReplacing && rotation.ReplacementDelivery == "") {
+		return writeManagerRotationCompleteOutput(out, opts.Output, ManagerRotationCompleteResult{
+			Completed:       true,
+			Reason:          "replacement_submitted",
+			RotationID:      rotation.ID,
+			Phase:           rotation.Phase,
+			HandoffArtifact: rotation.HandoffArtifact,
+		})
+	}
+
+	if rotation.Phase == RotationRequested {
+		result, frontmatter, artifact, validateErr := validateManagerHandoffResult(
+			state,
+			*rotation,
+			sourceSession,
+		)
+		if validateErr != nil {
+			state = recordManagerRotationError(state, opts.StateFile, *rotation, "validate", validateErr)
+			if saveErr := store.Save(opts.StateFile, state); saveErr != nil {
+				return errors.Join(validateErr, saveErr)
+			}
+			return validateErr
+		}
+		rawResult, err := json.Marshal(result)
+		if err != nil {
+			return err
+		}
+		next := *rotation
+		next.Phase = RotationHandoffReady
+		next.HandoffArtifact = artifact
+		next.HandoffResult = rawResult
+		next.UpdatedAt = clockOrNow(d)().Format(time.RFC3339Nano)
+		next.LastError = ""
+		state.Rotations.Manager = &next
+		if err := store.Save(opts.StateFile, state); err != nil {
+			return err
+		}
+		_ = frontmatter
+		rotation = &next
+	}
+	if rotation.Phase != RotationHandoffReady && rotation.Phase != RotationReplacing {
+		return fmt.Errorf("manager rotation %q is in phase %q", rotation.ID, rotation.Phase)
+	}
+
+	paneID := managerDeliveryPane(state)
+	if paneID == "" {
+		err := errors.New("manager pane is required for session replacement")
+		state = recordManagerRotationError(state, opts.StateFile, *rotation, "replace", err)
+		_ = store.Save(opts.StateFile, state)
+		return err
+	}
+	if rotation.Phase == RotationHandoffReady {
+		next := *rotation
+		next.Phase = RotationReplacing
+		next.ReplacementDelivery = RotationPasteAndSubmit
+		next.PastedPaneID = ""
+		next.UpdatedAt = clockOrNow(d)().Format(time.RFC3339Nano)
+		state.Rotations.Manager = &next
+		state.Delivery.Status = "replacing"
+		state.Delivery.ManagerPaneID = paneID
+		if err := store.Save(opts.StateFile, state); err != nil {
+			return err
+		}
+		rotation = &next
+	}
+
+	tmux := tmuxClient(d)
+	pane := TmuxPane{ID: paneID}
+	if rotation.ReplacementDelivery == RotationPasteAndSubmit {
+		if err := tmux.PasteText(ctx, pane, "/new"); err != nil {
+			state = recordManagerRotationError(state, opts.StateFile, *rotation, "paste_new", err)
+			_ = store.Save(opts.StateFile, state)
+			return err
+		}
+		next := *rotation
+		next.ReplacementDelivery = RotationSubmitOnly
+		next.PastedPaneID = paneID
+		next.UpdatedAt = clockOrNow(d)().Format(time.RFC3339Nano)
+		state.Rotations.Manager = &next
+		if err := store.Save(opts.StateFile, state); err != nil {
+			return err
+		}
+		rotation = &next
+	}
+	if rotation.ReplacementDelivery == RotationSubmitOnly {
+		if rotation.PastedPaneID != paneID {
+			return fmt.Errorf(
+				"manager rotation %q pasted /new into pane %q, not %q",
+				rotation.ID,
+				rotation.PastedPaneID,
+				paneID,
+			)
+		}
+		if err := tmux.SendKeys(ctx, pane, []string{"Enter"}); err != nil {
+			state = recordManagerRotationError(state, opts.StateFile, *rotation, "submit_new", err)
+			_ = store.Save(opts.StateFile, state)
+			return err
+		}
+		next := *rotation
+		next.ReplacementDelivery = ""
+		next.UpdatedAt = clockOrNow(d)().Format(time.RFC3339Nano)
+		next.LastError = ""
+		state.Rotations.Manager = &next
+		state.LastActionCard = nil
+		if err := store.Save(opts.StateFile, state); err != nil {
+			return err
+		}
+		rotation = &next
+	}
+	return writeManagerRotationCompleteOutput(out, opts.Output, ManagerRotationCompleteResult{
+		Completed:       true,
+		Reason:          "replacement_submitted",
+		RotationID:      rotation.ID,
+		Phase:           rotation.Phase,
+		HandoffArtifact: rotation.HandoffArtifact,
+	})
+}
+
+func validateManagerRotationCompleteOptions(opts ManagerRotationCompleteOptions) error {
+	if strings.TrimSpace(opts.StateFile) == "" {
+		return errors.New("state-file is required")
+	}
+	if strings.TrimSpace(opts.RotationID) == "" {
+		return errors.New("rotation-id is required")
+	}
+	if strings.TrimSpace(opts.SessionPath) == "" {
+		return errors.New("session-path is required")
+	}
+	switch strings.ToLower(strings.TrimSpace(opts.Output)) {
+	case "", "text", "json":
+		return nil
+	default:
+		return fmt.Errorf("unsupported output format %q", opts.Output)
+	}
+}
+
+func requireManagerRotation(
+	state ManagerState,
+	rotationID, sourceSession string,
+) (*SessionRotation, error) {
+	rotation := state.Rotations.Manager
+	if rotation == nil || rotation.Role != RotationRoleManager {
+		return nil, errors.New("no manager rotation is pending")
+	}
+	if rotation.ID != strings.TrimSpace(rotationID) {
+		return nil, fmt.Errorf("manager rotation %q does not match %q", rotationID, rotation.ID)
+	}
+	if !sameCleanPath(rotation.SourceSessionPath, sourceSession) {
+		return nil, fmt.Errorf(
+			"manager source session %q does not match rotation source %q",
+			sourceSession,
+			rotation.SourceSessionPath,
+		)
+	}
+	return rotation, nil
+}
+
+func validateManagerHandoffResult(
+	state ManagerState,
+	rotation SessionRotation,
+	sessionPath string,
+) (ManagerHandoffResult, ManagerHandoffFrontmatter, string, error) {
+	if !sameCleanPath(rotation.SourceSessionPath, sessionPath) {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", errors.New(
+			"manager handoff source session does not own the rotation",
+		)
+	}
+	text, err := ExtractFinalAssistantTextFromSession(sessionPath)
+	if err != nil {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+	}
+	rawYAML, err := workflowqrspi.ExtractQRSPIResultYAML(text)
+	if err != nil {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+	}
+	var envelope struct {
+		Result ManagerHandoffResult `yaml:"qrspi_result"`
+	}
+	if err := yaml.Unmarshal([]byte(rawYAML), &envelope); err != nil {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", fmt.Errorf(
+			"parse manager handoff result: %w",
+			err,
+		)
+	}
+	result := envelope.Result
+	if result.Stage != "q-manager" || result.Status != "handoff" ||
+		strings.TrimSpace(result.Outcome) != "" || strings.TrimSpace(result.Artifact) == "" {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", fmt.Errorf(
+			"manager handoff result must use stage q-manager, status handoff, no outcome, and one artifact",
+		)
+	}
+	sourceCwd := firstNonEmpty(strings.TrimSpace(state.SourceCwd), strings.TrimSpace(state.RepoID))
+	artifact, err := resolvePlanArtifact(
+		state.RepoID,
+		state.CanonicalPlanDir,
+		sourceCwd,
+		result.Artifact,
+	)
+	if err != nil {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+	}
+	frontmatter, err := readManagerHandoffFrontmatter(artifact)
+	if err != nil {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", err
+	}
+	if frontmatter.Stage != "q-manager" || frontmatter.Status != "in_progress" ||
+		frontmatter.HandoffType != "q-manager-operational" ||
+		frontmatter.RotationID != rotation.ID {
+		return ManagerHandoffResult{}, ManagerHandoffFrontmatter{}, "", fmt.Errorf(
+			"manager handoff frontmatter does not match rotation %q",
+			rotation.ID,
+		)
+	}
+	return result, frontmatter, artifact, nil
+}
+
+func readManagerHandoffFrontmatter(path string) (ManagerHandoffFrontmatter, error) {
+	file, err := os.Open(path)
+	if err != nil {
+		return ManagerHandoffFrontmatter{}, err
+	}
+	defer file.Close()
+	scanner := bufio.NewScanner(file)
+	if !scanner.Scan() || strings.TrimSpace(scanner.Text()) != "---" {
+		return ManagerHandoffFrontmatter{}, errors.New("manager handoff must start with YAML frontmatter")
+	}
+	var raw strings.Builder
+	closed := false
+	for scanner.Scan() {
+		if strings.TrimSpace(scanner.Text()) == "---" {
+			closed = true
+			break
+		}
+		raw.WriteString(scanner.Text())
+		raw.WriteByte('\n')
+	}
+	if err := scanner.Err(); err != nil {
+		return ManagerHandoffFrontmatter{}, err
+	}
+	if !closed {
+		return ManagerHandoffFrontmatter{}, errors.New("manager handoff frontmatter is not closed")
+	}
+	var frontmatter ManagerHandoffFrontmatter
+	if err := yaml.Unmarshal([]byte(raw.String()), &frontmatter); err != nil {
+		return ManagerHandoffFrontmatter{}, fmt.Errorf("parse manager handoff frontmatter: %w", err)
+	}
+	return frontmatter, nil
+}
+
+func recordManagerRotationError(
+	state ManagerState,
+	stateFile string,
+	rotation SessionRotation,
+	phase string,
+	rotationErr error,
+) ManagerState {
+	next := rotation
+	next.LastError = rotationErr.Error()
+	next.UpdatedAt = clockOrNow(deps{})().Format(time.RFC3339Nano)
+	state.Rotations.Manager = &next
+	state.LastActionCard = &ManagerActionCard{
+		Kind:     ActionManagerRotationFailed,
+		Severity: "warning",
+		Summary:  "manager session rotation remains recoverable after a failed step",
+		Evidence: []string{
+			fmt.Sprintf("rotation: %s", rotation.ID),
+			fmt.Sprintf("phase: %s", phase),
+			rotationErr.Error(),
+		},
+		RecommendedAction: "retry the exact manager rotation command after inspecting persisted refs",
+		SafeCommand: fmt.Sprintf(
+			"vamos qrspi manager-rotation-complete --state-file %s --rotation-id %s --session-path %s",
+			stateFile,
+			rotation.ID,
+			rotation.SourceSessionPath,
+		),
+		ContinueCommand: continueCommand(stateFile),
+		RequiresHuman:   false,
+	}
+	return state
+}
+
+func writeManagerRotationCompleteOutput(
+	out io.Writer,
+	mode string,
+	result ManagerRotationCompleteResult,
+) error {
+	if strings.EqualFold(strings.TrimSpace(mode), "json") {
+		return json.NewEncoder(out).Encode(result)
+	}
+	_, err := fmt.Fprintf(
+		out,
+		"manager rotation: %s; phase %s; handoff %s\n",
+		result.Reason,
+		result.Phase,
+		result.HandoffArtifact,
+	)
+	return err
+}
+
+func RunManagerRotationClaim(
+	ctx context.Context,
+	opts ManagerRotationClaimOptions,
+	d deps,
+	out io.Writer,
+) error {
+	if strings.TrimSpace(opts.StateFile) == "" || strings.TrimSpace(opts.RotationID) == "" ||
+		strings.TrimSpace(opts.ManagerPane) == "" || strings.TrimSpace(opts.PreviousSessionPath) == "" ||
+		strings.TrimSpace(opts.SuccessorSessionPath) == "" {
+		return errors.New("state-file, rotation-id, manager-pane, previous-session-path, and session-path are required")
+	}
+	previous, err := canonicalSessionPath(opts.PreviousSessionPath)
+	if err != nil {
+		return err
+	}
+	successor, err := canonicalSessionPath(opts.SuccessorSessionPath)
+	if err != nil {
+		return err
+	}
+	opts.PreviousSessionPath = previous
+	opts.SuccessorSessionPath = successor
+	out = ensureWriter(out)
+	store := stateStore(d, "", clockOrNow(d))
+	lock, err := store.AcquireOperationLock(ctx, opts.StateFile)
+	if err != nil {
+		return err
+	}
+	defer lock.Release()
+	state, err := store.Load(opts.StateFile)
+	if err != nil {
+		return err
+	}
+	next, result, err := claimManagerSuccessor(state, opts, clockOrNow(d)())
+	if err != nil {
+		return err
+	}
+	if err := store.Save(opts.StateFile, next); err != nil {
+		return err
+	}
+	if strings.EqualFold(strings.TrimSpace(opts.Output), "json") {
+		return json.NewEncoder(out).Encode(result)
+	}
+	if result.Claimed {
+		_, err = fmt.Fprintf(out, "manager rotation claimed: %s\n", opts.RotationID)
+	} else {
+		_, err = fmt.Fprintf(out, "manager rotation claim skipped: %s\n", result.Reason)
+	}
+	return err
+}
+
+func claimManagerSuccessor(
+	state ManagerState,
+	opts ManagerRotationClaimOptions,
+	now time.Time,
+) (ManagerState, ManagerRotationClaimResult, error) {
+	original := state
+	rotation := state.Rotations.Manager
+	if rotation == nil || rotation.Role != RotationRoleManager ||
+		rotation.ID != strings.TrimSpace(opts.RotationID) {
+		return original, ManagerRotationClaimResult{}, errors.New("manager rotation claim does not match pending rotation")
+	}
+	if rotation.Phase != RotationReplacing {
+		return original, ManagerRotationClaimResult{}, fmt.Errorf(
+			"manager rotation %q is in phase %q, not replacing",
+			rotation.ID,
+			rotation.Phase,
+		)
+	}
+	paneID := managerDeliveryPane(state)
+	if paneID == "" || paneID != strings.TrimSpace(opts.ManagerPane) {
+		return original, ManagerRotationClaimResult{}, fmt.Errorf(
+			"manager pane %q does not match persisted pane %q",
+			opts.ManagerPane,
+			paneID,
+		)
+	}
+	if !sameCleanPath(rotation.SourceSessionPath, opts.PreviousSessionPath) {
+		return original, ManagerRotationClaimResult{}, errors.New("previous session does not match rotation source")
+	}
+	if sameCleanPath(opts.PreviousSessionPath, opts.SuccessorSessionPath) {
+		return original, ManagerRotationClaimResult{}, errors.New("successor session must differ from source session")
+	}
+	if rotation.SuccessorSessionPath != "" &&
+		!sameCleanPath(rotation.SuccessorSessionPath, opts.SuccessorSessionPath) {
+		return original, ManagerRotationClaimResult{}, errors.New("a different successor already claimed the rotation")
+	}
+	next := *rotation
+	next.SuccessorSessionPath = opts.SuccessorSessionPath
+	next.UpdatedAt = now.Format(time.RFC3339Nano)
+	next.LastError = ""
+	state.Rotations.Manager = &next
+	state.ManagerSessionPath = opts.SuccessorSessionPath
+	return state, ManagerRotationClaimResult{
+		Claimed: true,
+		Reason:  "claimed",
+		Kickoff: managerRotationKickoff(state, next, opts.StateFile),
+	}, nil
+}
+
+func managerRotationKickoff(state ManagerState, rotation SessionRotation, stateFile string) string {
+	return fmt.Sprintf(
+		"Continue q-manager in this fresh same-pane session. Read .pi/skills/q-manager/SKILL.md, then read the operational handoff %s. Current graph node: %s. Local manager state: %s. Resume the wake-driven manager loop from the handoff; do not duplicate any persisted child continuation.",
+		rotation.HandoffArtifact,
+		state.Workflow.CurrentNodeID,
+		stateFile,
+	)
+}
+
+func acknowledgeManagerRotationReady(
+	state ManagerState,
+	opts ManagerReadyOptions,
+	now time.Time,
+) (ManagerState, error) {
+	rotation := state.Rotations.Manager
+	if rotation == nil {
+		return state, nil
+	}
+	if rotation.Phase == RotationSuccessorReady {
+		if strings.TrimSpace(opts.RotationID) != "" && opts.RotationID != rotation.ID {
+			return state, errors.New("manager-ready rotation ID does not match current rotation")
+		}
+		if strings.TrimSpace(opts.SessionPath) != "" &&
+			!sameCleanPath(opts.SessionPath, rotation.SuccessorSessionPath) {
+			return state, errors.New("manager-ready session does not match current successor")
+		}
+		return state, nil
+	}
+	if rotation.Phase != RotationReplacing {
+		return state, nil
+	}
+	if strings.TrimSpace(opts.RotationID) == "" || opts.RotationID != rotation.ID {
+		return state, errors.New("manager-ready requires the exact pending rotation ID")
+	}
+	if strings.TrimSpace(opts.SessionPath) == "" {
+		return state, errors.New("manager-ready requires the successor session path")
+	}
+	sessionPath, err := canonicalSessionPath(opts.SessionPath)
+	if err != nil {
+		return state, err
+	}
+	if !sameCleanPath(sessionPath, rotation.SuccessorSessionPath) ||
+		!sameCleanPath(sessionPath, state.ManagerSessionPath) {
+		return state, errors.New("manager-ready session does not own the claimed successor")
+	}
+	paneID := managerDeliveryPane(state)
+	if strings.TrimSpace(opts.ManagerPane) == "" || strings.TrimSpace(opts.ManagerPane) != paneID {
+		return state, errors.New("manager-ready pane does not match persisted replacement pane")
+	}
+	next := *rotation
+	next.Phase = RotationSuccessorReady
+	next.UpdatedAt = now.Format(time.RFC3339Nano)
+	next.LastError = ""
+	state.Rotations.Manager = &next
+	state.Delivery.Status = "ready"
+	state.LastActionCard = nil
+	return state, nil
+}
+
 func completeChildRotation(
 	state ManagerState,
 	source ChildRunRef,
 	continuation ChildRunRef,

