import { execFile } from "node:child_process";
import { readFile } from "node:fs/promises";
import { dirname } from "node:path";
import { promisify } from "node:util";
import type { ContextUsage, ExtensionAPI, ExtensionCommandContext } from "@earendil-works/pi-coding-agent";

const execFileAsync = promisify(execFile);
const maxCLIOutputBytes = 1024 * 1024;

type QManagerAction = "start-next" | "continue";

type ParsedArgs = {
	action: QManagerAction;
	passthrough: string[];
};

type QManagerCLIResult = {
	exitCode: number;
	stdout: string;
	stderr: string;
};

type RotationRequestResult = {
	requested: boolean;
	reason: string;
	rotationId?: string;
	stateFile?: string;
	prompt?: string;
};

type ManagerRotationClaimResult = {
	claimed: boolean;
	reason: string;
	kickoff?: string;
};

type ExecError = Error & { code?: unknown; stdout?: unknown; stderr?: unknown };

type ToolCallBlock = {
	type: string;
	id?: string;
	name?: string;
	arguments?: unknown;
};

export default function qManagerParentExtension(pi: ExtensionAPI): void {
	let boundStateFile = managedChild() ? undefined : nonEmpty(process.env.Q_MANAGER_STATE_FILE);
	let pendingRotationId = managedChild() ? undefined : nonEmpty(process.env.Q_MANAGER_ROTATION_ID);
	let claimedRotationId: string | undefined;
	let completingRotation = false;
	let requestingRotation = false;

	const bindStateFile = (stateFile: string | undefined): void => {
		if (managedChild() || !stateFile) return;
		boundStateFile = stateFile;
		process.env.Q_MANAGER_STATE_FILE = stateFile;
	};

	pi.registerCommand("q-manager", {
		description: "Start q-manager from conversation context, or run an explicit start-next/continue operation",
		getArgumentCompletions: (prefix) => {
			const actions = ["start-next", "continue"];
			const matches = actions.filter((action) => action.startsWith(prefix.trim()));
			return matches.length > 0 ? matches.map((action) => ({ value: action, label: action })) : null;
		},
		handler: async (args, ctx) => {
			let parsed: ParsedArgs | undefined;
			try {
				parsed = parseArgs(args);
			} catch (error) {
				ctx.ui.notify(error instanceof Error ? error.message : String(error), "error");
				return;
			}

			if (!parsed) {
				await startManagerAgent(pi, args, ctx);
				return;
			}

			const passthrough = parsed.passthrough.map((arg) => expandShellVariables(arg, ctx.cwd));
			const result = await runQManagerCLI(parsed.action, passthrough, ctx.cwd);
			publishCLIResult(ctx, result);
			if (result.exitCode !== 0) {
				ctx.ui.notify("q-manager CLI failed", "error");
				return;
			}
			bindStateFile(findStateMarker(result.stdout));
		},
	});

	pi.on("session_start", async (event, ctx) => {
		if (managedChild() || event.reason !== "new" || !event.previousSessionFile) return;
		const stateFile = nonEmpty(process.env.Q_MANAGER_STATE_FILE);
		const rotationId = nonEmpty(process.env.Q_MANAGER_ROTATION_ID);
		const successorSession = ctx.sessionManager.getSessionFile();
		const managerPane = nonEmpty(process.env.TMUX_PANE);
		if (!stateFile || !rotationId || !successorSession || !managerPane) return;

		try {
			const claim = await runCLIJSON<ManagerRotationClaimResult>(
				[
					"qrspi",
					"manager-rotation-claim",
					"--state-file",
					stateFile,
					"--rotation-id",
					rotationId,
					"--manager-pane",
					managerPane,
					"--previous-session-path",
					event.previousSessionFile,
					"--session-path",
					successorSession,
					"--output",
					"json",
				],
				ctx.cwd,
			);
			if (claim.claimed && claim.kickoff) {
				boundStateFile = stateFile;
				pendingRotationId = rotationId;
				claimedRotationId = rotationId;
				pi.sendUserMessage(claim.kickoff);
			}
		} catch (error) {
			ctx.ui.notify(`q-manager rotation claim failed: ${errorMessage(error)}`, "error");
		}
	});

	pi.on("turn_end", async (event, ctx) => {
		if (managedChild()) return;
		bindStateFile(stateFileFromCompletedManagerCLI(event.message.content, event.toolResults));
		if (requestingRotation || !boundStateFile || pendingRotationId) return;
		const sessionPath = ctx.sessionManager.getSessionFile();
		const usage = ctx.getContextUsage();
		const usageArgs = rotationUsageArgs(usage);
		if (!sessionPath || usageArgs.length === 0) return;

		requestingRotation = true;
		try {
			const request = await runCLIJSON<RotationRequestResult>(
				[
					"qrspi",
					"rotation-request",
					"--state-file",
					boundStateFile,
					"--role",
					"manager",
					"--session-path",
					sessionPath,
					...usageArgs,
					"--usage-source",
					"pi-extension-context",
					"--output",
					"json",
				],
				ctx.cwd,
			);
			if (request.requested && request.rotationId && request.prompt) {
				pendingRotationId = request.rotationId;
				process.env.Q_MANAGER_ROTATION_ID = request.rotationId;
				pi.sendUserMessage(request.prompt, { deliverAs: "steer" });
			}
		} catch (error) {
			ctx.ui.notify(`q-manager rotation request failed: ${errorMessage(error)}`, "warning");
		} finally {
			requestingRotation = false;
		}
	});

	pi.on("agent_settled", async (_event, ctx) => {
		if (managedChild() || completingRotation || !boundStateFile || !pendingRotationId) return;
		const sessionPath = ctx.sessionManager.getSessionFile();
		if (!sessionPath) return;
		completingRotation = true;
		try {
			await runCLI(
				[
					"qrspi",
					"manager-rotation-complete",
					"--state-file",
					boundStateFile,
					"--rotation-id",
					pendingRotationId,
					"--session-path",
					sessionPath,
				],
				ctx.cwd,
			);
		} catch (error) {
			ctx.ui.notify(`q-manager rotation completion failed: ${errorMessage(error)}`, "error");
		} finally {
			completingRotation = false;
		}
	});

	pi.on("agent_start", async (_event, ctx) => {
		if (managedChild() || !claimedRotationId || !boundStateFile) return;
		const sessionPath = ctx.sessionManager.getSessionFile();
		const managerPane = nonEmpty(process.env.TMUX_PANE);
		if (!sessionPath || !managerPane) return;
		try {
			await runCLI(
				[
					"qrspi",
					"manager-ready",
					"--state-file",
					boundStateFile,
					"--rotation-id",
					claimedRotationId,
					"--session-path",
					sessionPath,
					"--manager-pane",
					managerPane,
				],
				ctx.cwd,
			);
			claimedRotationId = undefined;
			pendingRotationId = undefined;
			delete process.env.Q_MANAGER_ROTATION_ID;
		} catch (error) {
			ctx.ui.notify(`q-manager successor readiness failed: ${errorMessage(error)}`, "error");
		}
	});

	pi.on("session_before_compact", () => {
		if (managedChild() || boundStateFile) return { cancel: true };
		return undefined;
	});
}

function parseArgs(args: string): ParsedArgs | undefined {
	const trimmed = args.trim();
	const firstToken = trimmed.match(/^\S+/)?.[0];
	if (firstToken !== "start-next" && firstToken !== "continue") return undefined;
	const parts = splitArgs(trimmed);
	const action = parts.shift() as QManagerAction;
	return { action, passthrough: parts };
}

async function startManagerAgent(pi: ExtensionAPI, args: string, ctx: ExtensionCommandContext): Promise<void> {
	const skill = pi.getCommands().find((command) => command.source === "skill" && command.name === "skill:q-manager");
	if (!skill) throw new Error("q-manager skill is not loaded");
	const skillText = await readFile(skill.sourceInfo.path, "utf8");
	const skillBody = skillText.replace(/^---\r?\n[\s\S]*?\r?\n---\r?\n?/, "").trim();
	const startupInput =
		args.trim() ||
		"Start or resume q-manager from the current conversation. Infer the next graph-safe action from the latest available QRSPI result or manager wake.";
	const prompt = `<skill name="q-manager" location="${skill.sourceInfo.path}">\nReferences are relative to ${dirname(skill.sourceInfo.path)}.\n\n${skillBody}\n</skill>\n\nManager startup input:\n${startupInput}`;
	pi.sendUserMessage(prompt, ctx.isIdle() ? undefined : { deliverAs: "steer" });
}

function splitArgs(input: string): string[] {
	const args: string[] = [];
	let current = "";
	let quote: '"' | "'" | undefined;
	let escaping = false;
	for (const char of input) {
		if (escaping) {
			current += char;
			escaping = false;
			continue;
		}
		if (char === "\\") {
			escaping = true;
			continue;
		}
		if (quote) {
			if (char === quote) quote = undefined;
			else current += char;
			continue;
		}
		if (char === '"' || char === "'") {
			quote = char;
			continue;
		}
		if (/\s/.test(char)) {
			if (current !== "") {
				args.push(current);
				current = "";
			}
			continue;
		}
		current += char;
	}
	if (escaping) current += "\\";
	if (quote) throw new Error("unterminated quoted argument");
	if (current !== "") args.push(current);
	return args;
}

function expandShellVariables(arg: string, cwd: string): string {
	return arg.replace(/\$\{([A-Za-z_][A-Za-z0-9_]*)\}|\$([A-Za-z_][A-Za-z0-9_]*)/g, (_match, braced, bare) => {
		const name = String(braced ?? bare);
		if (name === "PWD") return cwd;
		return process.env[name] ?? "";
	});
}

function rotationUsageArgs(usage: ContextUsage | undefined): string[] {
	if (!usage || usage.percent === null) return [];
	return ["--usage-percent", usage.percent.toFixed(1)];
}

async function runQManagerCLI(action: QManagerAction, args: string[], cwd: string): Promise<QManagerCLIResult> {
	return runCLIResult(["qrspi", action, ...args], cwd);
}

async function runCLI(args: string[], cwd: string): Promise<QManagerCLIResult> {
	const result = await runCLIResult(args, cwd);
	if (result.exitCode !== 0) {
		throw new Error(firstSignificantLine(result.stderr) ?? firstSignificantLine(result.stdout) ?? "q-manager CLI failed");
	}
	return result;
}

async function runCLIJSON<T>(args: string[], cwd: string): Promise<T> {
	const result = await runCLI(args, cwd);
	try {
		return JSON.parse(result.stdout) as T;
	} catch (error) {
		throw new Error(`invalid q-manager JSON: ${errorMessage(error)}`);
	}
}

async function runCLIResult(args: string[], cwd: string): Promise<QManagerCLIResult> {
	const bin = process.env.VAMOS_Q_MANAGER_BIN?.trim() || "vamos";
	try {
		const { stdout, stderr } = await execFileAsync(bin, args, { cwd, maxBuffer: maxCLIOutputBytes });
		return { exitCode: 0, stdout, stderr };
	} catch (error) {
		if (isExecError(error)) {
			return {
				exitCode: typeof error.code === "number" ? error.code : 1,
				stdout: String(error.stdout ?? ""),
				stderr: String(error.stderr ?? ""),
			};
		}
		throw error;
	}
}

function stateFileFromCompletedManagerCLI(content: unknown, toolResults: readonly unknown[]): string | undefined {
	if (!Array.isArray(content)) return undefined;
	const results = new Map<string, { isError: boolean; text: string }>();
	for (const raw of toolResults) {
		if (!raw || typeof raw !== "object") continue;
		const result = raw as { toolCallId?: unknown; isError?: unknown; content?: unknown };
		if (typeof result.toolCallId !== "string") continue;
		results.set(result.toolCallId, {
			isError: result.isError === true,
			text: textContent(result.content),
		});
	}
	for (const raw of content) {
		if (!raw || typeof raw !== "object") continue;
		const call = raw as ToolCallBlock;
		if (call.type !== "toolCall" || call.name !== "bash" || !call.id) continue;
		const command = bashCommand(call.arguments);
		if (!isManagerCLICommand(command)) continue;
		const result = results.get(call.id);
		if (!result || result.isError) continue;
		const marker = findStateMarker(result.text);
		if (marker) return marker;
	}
	return undefined;
}

function bashCommand(args: unknown): string {
	if (!args || typeof args !== "object") return "";
	const command = (args as { command?: unknown }).command;
	return typeof command === "string" ? command : "";
}

function isManagerCLICommand(command: string): boolean {
	return /(?:vamos\s+qrspi|go\s+run\s+\.\/cmd\/vamos-runtime\s+qrspi)\s+(?:start-next|continue)\b/.test(command);
}

function textContent(content: unknown): string {
	if (typeof content === "string") return content;
	if (!Array.isArray(content)) return "";
	return content
		.filter((block): block is { type: string; text: string } =>
			Boolean(block && typeof block === "object" && (block as { type?: unknown }).type === "text" && typeof (block as { text?: unknown }).text === "string"),
		)
		.map((block) => block.text)
		.join("\n");
}

function findStateMarker(stdout: string): string | undefined {
	for (const line of stdout.split(/\r?\n/)) {
		const match = line.match(/^state:\s+(.+?)\s*$/);
		if (match) return nonEmpty(match[1]);
	}
	return undefined;
}

function managedChild(): boolean {
	return Boolean(nonEmpty(process.env.Q_MANAGER_CHILD_ID));
}

function nonEmpty(value: string | undefined): string | undefined {
	const trimmed = value?.trim();
	return trimmed ? trimmed : undefined;
}

function isExecError(error: unknown): error is ExecError {
	return error instanceof Error && ("stdout" in error || "stderr" in error || "code" in error);
}

function publishCLIResult(ctx: ExtensionCommandContext, result: QManagerCLIResult): void {
	const stdoutLine = firstSignificantLine(result.stdout);
	if (stdoutLine) ctx.ui.notify(`q-manager: ${stdoutLine}`, result.exitCode === 0 ? "info" : "error");
	const stderrLine = firstSignificantLine(result.stderr);
	if (stderrLine) ctx.ui.notify(`q-manager stderr: ${stderrLine}`, result.exitCode === 0 ? "warning" : "error");
}

function firstSignificantLine(text: string): string | undefined {
	return text
		.split(/\r?\n/)
		.map((line) => line.trim())
		.find((line) => line.length > 0);
}

function errorMessage(error: unknown): string {
	return error instanceof Error ? error.message : String(error);
}

