func TestManagerRotationCompleteValidatesBeforeExactPaneNew(t *testing.T) {
	state, stateFile, sourceSession, rotationID := managerRotationFixture(t, true)
	saveManagerState(t, stateFile, state)
	tmux := &recordingTmux{}
	var out strings.Builder
	if err := RunManagerRotationComplete(
		t.Context(),
		ManagerRotationCompleteOptions{
			StateFile: stateFile, RotationID: rotationID,
