func TestManagerRotationClaimAndReadyRequireExactPredecessor(t *testing.T) {
	state, stateFile, sourceSession, rotationID := managerRotationFixture(t, true)
	state.Rotations.Manager.Phase = RotationReplacing
	state.Rotations.Manager.ReplacementDelivery = ""
	state.Delivery.Status = "replacing"
	successor := writePiSession(t, filepath.Join(filepath.Dir(sourceSession), "successors"), "successor.jsonl", "manager-successor", state.SourceCwd, assistantLine("fresh"))
	other := writePiSession(t, filepath.Join(filepath.Dir(sourceSession), "others"), "other.jsonl", "manager-other", state.SourceCwd, assistantLine("other"))

	bad := ManagerRotationClaimOptions{
		StateFile: stateFile, RotationID: rotationID, ManagerPane: "%manager",
		PreviousSessionPath: other, SuccessorSessionPath: successor,
	}
	if _, _, err := claimManagerSuccessor(state, bad, time.Now()); err == nil {
		t.Fatal("mismatched predecessor claimed rotation")
	}
	good := bad
	good.PreviousSessionPath = sourceSession
	claimed, result, err := claimManagerSuccessor(state, good, time.Now())
	if err != nil || !result.Claimed || !strings.Contains(result.Kickoff, state.Rotations.Manager.HandoffArtifact) ||
		!sameCleanPath(claimed.ManagerSessionPath, successor) ||
		claimed.Rotations.Manager.Phase != RotationReplacing {
		t.Fatalf("claim=%+v result=%+v err=%v", claimed.Rotations.Manager, result, err)
	}
	ready, err := acknowledgeManagerRotationReady(claimed, ManagerReadyOptions{
		RotationID: rotationID, SessionPath: successor, ManagerPane: "%manager",
	}, time.Now())
	if err != nil || ready.Rotations.Manager.Phase != RotationSuccessorReady ||
		ready.Delivery.Status != "ready" {
		t.Fatalf("ready=%+v delivery=%+v err=%v", ready.Rotations.Manager, ready.Delivery, err)
	}
	if _, err := acknowledgeManagerRotationReady(claimed, ManagerReadyOptions{
		RotationID: rotationID, SessionPath: other, ManagerPane: "%manager",
	}, time.Now()); err == nil {
		t.Fatal("unclaimed successor marked ready")
	}
}

