func TestDeliveryQueuesWhileManagerReplacingAndFlushesAfterExactSuccessorReady(t *testing.T) {
	dir := t.TempDir()
	stateFile := filepath.Join(dir, "state.json")
	source := writePiSession(t, filepath.Join(dir, "sessions"), "source.jsonl", "manager-source", dir, assistantLine("source"))
	successor := writePiSession(t, filepath.Join(dir, "sessions"), "successor.jsonl", "manager-successor", dir, assistantLine("successor"))
	state := ManagerState{
		ManagerPaneID: "%manager", ManagerSessionPath: successor,
		Delivery: ManagerDeliveryState{Status: "replacing", ManagerPaneID: "%manager"},
		Rotations: RotationState{Manager: &SessionRotation{
			ID: "rotation-1", Role: RotationRoleManager, Phase: RotationReplacing,
			SourceSessionPath: source, SuccessorSessionPath: successor,
		}},
		ActiveChild: &ChildRunRef{ID: "child-1", Generation: 1, LifecycleStatus: "completed"},
	}
	status := ChildCompletionStatus{
		Validated: true, ChildID: "child-1", DeliveryID: "wake-1",
		Result: ChildCompletionResult{Stage: "plan", Status: "complete", Artifact: "artifact"},
	}
	tmux := &recordingTmux{}
	queued, wake, err := queueOrDeliverWake(t.Context(), stateFile, state, status, deps{Tmux: tmux})
	if err != nil {
		t.Fatal(err)
	}
	if wake.Mode != "queue" || wake.Reason != "manager_replacing" ||
		queued.Delivery.QueuedWake == nil || len(tmux.pastes) != 0 {
