	}
	saveManagerState(t, stateFile, queued)
	if err := RunManagerReady(t.Context(), ManagerReadyOptions{
		StateFile: stateFile, ManagerPane: "%manager", RotationID: "rotation-1", SessionPath: successor,
	}, deps{Tmux: tmux}, &strings.Builder{}); err != nil {
		t.Fatal(err)
	}
	loaded := loadManagerState(t, stateFile)
	if loaded.Rotations.Manager.Phase != RotationSuccessorReady ||
		loaded.Delivery.Status != "ready" || loaded.Delivery.QueuedWake != nil ||
		loaded.Delivery.LastDeliveryID != "wake-1" || len(tmux.pastes) != 1 {
		t.Fatalf("rotation=%+v delivery=%+v pastes=%#v", loaded.Rotations.Manager, loaded.Delivery, tmux.pastes)
	}
}

