func TestRotationCommandSurfaceAndPersistedThreshold(t *testing.T) {
	fixture := newManagerFlowFixture(t)
	initOut, err := executeManagerCommand(
		deps{StateRoot: fixture.stateRootFunc, Clock: fixture.clock},
		"init",
		"--plan-dir",
		fixture.planDir,
		"--project-root",
		fixture.projectRoot,
		"--rotation-threshold-percent",
		"82",
	)
	if err != nil {
		t.Fatalf("init rotation threshold error = %v", err)
	}
	stateFile := eventRefString(t, initOut, "stateFile")
	state := loadManagerState(t, stateFile)
	if state.Rotations.Config.ThresholdPercent != 82 {
		t.Fatalf("threshold = %v, want 82", state.Rotations.Config.ThresholdPercent)
	}
	updated, _, err := resolveOrInitStartState(
		t.Context(),
		StartNextOptions{StateFile: stateFile, RotationThresholdPercent: 91},
		deps{Clock: fixture.clock},
	)
	if err != nil {
		t.Fatalf("update existing rotation threshold error = %v", err)
	}
	if updated.Rotations.Config.ThresholdPercent != 91 ||
		loadManagerState(t, stateFile).Rotations.Config.ThresholdPercent != 91 {
		t.Fatalf(
			"updated threshold = %v, want durable 91",
			updated.Rotations.Config.ThresholdPercent,
		)
	}

	childState, opts := rotationChildFixture(t)
	childState.Rotations.Config.ThresholdPercent = 75
	rotationStateFile := filepath.Join(fixture.dir, "rotation-state.json")
	saveManagerState(t, rotationStateFile, childState)
	validOut, err := executeManagerCommand(
		deps{Clock: fixture.clock},
		"rotation-request",
		"--state-file",
		rotationStateFile,
		"--role",
		"child",
		"--child-id",
		opts.ChildID,
		"--session-path",
		opts.SessionPath,
		"--usage-percent",
		"75",
		"--output",
		"json",
	)
	if err != nil {
		t.Fatalf("rotation-request command error = %v", err)
	}
	if !strings.Contains(validOut, `"requested": true`) ||
		!strings.Contains(validOut, `"rotationId":`) {
		t.Fatalf("rotation output = %q", validOut)
	}
	persisted := loadManagerState(t, rotationStateFile)
	if persisted.Rotations.Child == nil ||
		persisted.Rotations.Child.Phase != RotationRequested {
		t.Fatalf("persisted rotation = %+v", persisted.Rotations.Child)
	}

	for _, args := range [][]string{
		{"rotation-request", "--state-file", rotationStateFile, "--role", "invalid", "--session-path", opts.SessionPath, "--usage-percent", "75"},
		{"rotation-request", "--state-file", rotationStateFile, "--role", "child", "--child-id", opts.ChildID, "--session-path", opts.SessionPath, "--usage-tokens", "10"},
		{"rotation-request", "--state-file", rotationStateFile, "--role", "child", "--child-id", opts.ChildID, "--session-path", opts.SessionPath, "--usage-percent", "-1"},
	} {
		stdout, stderr, err := executeManagerCommandWithErr(deps{}, args...)
		if err == nil {
			t.Fatalf("command %v succeeded: %q", args, stdout)
		}
		if strings.Contains(stdout+stderr, "Usage:") {
			t.Fatalf(
				"command %v printed usage: stdout=%q stderr=%q",
				args,
				stdout,
				stderr,
			)
		}
	}
}

